mapper.select:
SELECT nv.hoTen, SUM(ltd.luongCoBan * cx.tiLeThuLao) AS tongLuong, COUNT(DISTINCT cx.maChuyen) AS tongSoChuyen FROM NhanVien nv JOIN PhanCong pc ON nv.maNhanVien = pc.maNhanVien AND pc.vaiTro = #{role} JOIN ChuyenXe cx ON pc.maXe = cx.maXe AND pc.maTuyen = cx.maTuyen AND pc.maChuyen = cx.maChuyen JOIN TuyenDuong td ON cx.maTuyen = td.maTuyen JOIN LuongTuyenDuong ltd ON td.maLuongTuyen = ltd.maLuongTuyen WHERE cx.tinhTrangChuyen = 'Hoàn thành' AND DATE(cx.ngayGioDen) >= #{fromDate} AND DATE(cx.ngayGioDen) < #{toDate}
AND (nv.hoTen LIKE CONCAT('%', #{keyword}, '%') OR nv.soDienThoai LIKE CONCAT('%', #{keyword}, '%'))
GROUP BY nv.hoTen;
